import { jsPDF } from "jspdf"

var nunitoFont = '';

var callAddNunito = function () {
    this.addFileToVFS('NunitoSans-normal.ttf', nunitoFont);
    this.addFont('NunitoSans-normal.ttf', 'NunitoSans', 'normal');
};
jsPDF.API.events.push(['addFonts', callAddNunito]);


var unboundedFont = '';

var callAddUnbounded = function () {
    this.addFileToVFS('UnboundedBold-normal.ttf', unboundedFont);
    this.addFont('UnboundedBold-normal.ttf', 'UnboundedBold', 'bold');
};
jsPDF.API.events.push(['addFonts', callAddUnbounded]);

// === СООБЩЕНИЕ О ЗАГРУЗКЕ ===
jsPDF.API.events.push(['initialized', function () {
    window.pdfFontsLoaded = true;
    jsPDF.API.events.push(['fontsLoaded', function() {}]);
}]);



